function StatusAnnouncer() {
  const [message, setMessage] = useState('');

  const save = () => {
    setMessage('저장되었습니다.');
  };

  return (
    <div>
      <button onClick={save}>저장</button>

      {/* 비긴급 상태 메시지 */}
      <div
        role="status"
        aria-live="polite"
        aria-atomic="true"
        className="sr-only"
      >
        {message}
      </div>
    </div>
  );
}
